it("should handle negative coordinates", () => {
  const gol = new GameOfLife();
  gol.addCell(-2, -3);
  gol.addCell(-1, -2);
  gol.addCell(0, -3);
  const nextGen = gol.nextGeneration();
  expect(nextGen).toEqual([[-1, -3], [-1, -2], [0, -2]]);
});
